#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long sumAttA=0, sumDefA=0, sumAttP=0, sumDefP=0;
        for(int i=0;i<N;i++){ int x; scanf("%d", &x); sumAttA+=x; }
        for(int i=0;i<N;i++){ int x; scanf("%d", &x); sumDefA+=x; }
        for(int i=0;i<N;i++){ int x; scanf("%d", &x); sumAttP+=x; }
        for(int i=0;i<N;i++){ int x; scanf("%d", &x); sumDefP+=x; }
        if(sumAttA>sumAttP && sumDefA>sumDefP) printf("A\n");
        else if(sumAttP>sumAttA && sumDefP>sumDefA) printf("P\n");
        else printf("DRAW\n");
    }
    return 0;
}

