code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            long sumAttA = 0, sumDefA = 0, sumAttP = 0, sumDefP = 0;
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) sumAttA += Integer.parseInt(st.nextToken());
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) sumDefA += Integer.parseInt(st.nextToken());
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) sumAttP += Integer.parseInt(st.nextToken());
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) sumDefP += Integer.parseInt(st.nextToken());
            if (sumAttA > sumAttP && sumDefA > sumDefP) sb.append("A\n");
            else if (sumAttP > sumAttA && sumDefP > sumDefA) sb.append("P\n");
            else sb.append("DRAW\n");
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        sumAttA = sum(next(it) for _ in range(N))
        sumDefA = sum(next(it) for _ in range(N))
        sumAttP = sum(next(it) for _ in range(N))
        sumDefP = sum(next(it) for _ in range(N))
        if sumAttA > sumAttP and sumDefA > sumDefP:
            out_lines.append("A")
        elif sumAttP > sumAttA and sumDefP > sumDefA:
            out_lines.append("P")
        else:
            out_lines.append("DRAW")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

